matching_processes.command_line:
C:\Windows\System32\WindowsPowerShell\v1.0\powershell.EXE -NoProfile -NonInteractive -ExecutionPolicy Bypass -Command "$global:LASTEXITCODE = $null
& {
$ErrorActionPreference='Stop'
Write-Host 'AIMO_SANDBOX_TESTLIFE_SCHOOL_COMPAT_PROOF_START'
$dummy=$null
$aimo=$null
$lockPath='.runtime/compact_memory_intake_v1/MERGE_QUEUE.lock.json'
$runId='aimo_testlife_school_compat_20260706_113300'
$runRoot=\"operations/autonomous_inner_motor/test_life_runs/$runId\"
$stopPath=Join-Path $runRoot 'STOP_REQUESTED.txt'
try {
  if(Test-Path $runRoot){ Remove-Item $runRoot -Recurse -Force }
  New-Item -ItemType Directory -Force -Path (Split-Path $lockPath -Parent) | Out-Null
  [ordered]@{ schema='test_merge_queue_lock_v1'; status='ACTIVE_TEST_LOCK'; created_at=(Get-Date).ToString('o'); purpose='AIMO SandboxTestLife compatibility proof backoff signal' } | ConvertTo-Json -Depth 20 | Set-Content -LiteralPath $lockPath -Encoding UTF8
  $dummy = Start-Process -FilePath 'powershell' -ArgumentList @('-NoProfile','-Command',\"`$Host.UI.RawUI.WindowTitle='run_agent_school_dummy_for_aimo_testlife_compat'; Start-Sleep -Seconds 120\") -PassThru
  Start-Sleep -Seconds 2
  $stdout=\".runtime/aimo_testlife_school_compat_$runId.stdout.log\"
  $stderr=\".runtime/aimo_testlife_school_compat_$runId.stderr.log\"
  $aimo = Start-Process -FilePath 'powershell' -ArgumentList @('-NoProfile','-ExecutionPolicy','Bypass','-File','operations/autonomous_inner_motor/run_autonomous_inner_motor.ps1','-Mode','SandboxTestLife','-RunId',$runId) -WorkingDirectory (Get-Location).Path -RedirectStandardOutput $stdout -RedirectStandardError $stderr -PassThru
  Start-Sleep -Seconds 10
  New-Item -ItemType Directory -Force -Path $runRoot | Out-Null
  'STOP_REQUESTED_BY_COMPAT_PROOF' | Set-Content -LiteralPath $stopPath -Encoding UTF8
  for($i=0;$i -lt 90;$i++){
    Start-Sleep -Seconds 1
    $proc=Get-Process -Id $aimo.Id -ErrorAction SilentlyContinue
    if(-not $proc){ break }
  }
  if(Get-Process -Id $aimo.Id -ErrorAction SilentlyContinue){ throw 'AIMO_TESTLIFE_DID_NOT_STOP_AFTER_STOP_FILE' }
  Write-Host 'AIMO_STDOUT_START'; if(Test-Path $stdout){ Get-Content $stdout -Tail 30 | ForEach-Object{Write-Host $_} }; Write-Host 'AIMO_STDOUT_END'
  Write-Host 'AIMO_STDERR_START'; if(Test-Path $stderr){ Get-Content $stderr -Tail 30 | ForEach-Object{Write-Host $_} }; Write-Host 'AIMO_STDERR_END'
  $proof=Join-Path $runRoot 'TEST_LIFE_PROOF.json'
  if(-not (Test-Path $proof)){ throw 'TEST_LIFE_PROOF_MISSING' }
  $p=Get-Content $proof -Raw|ConvertFrom-Json
  if([bool]$p.school_state.active_detected -ne $true){ throw 'TESTLIFE_SCHOOL_ACTIVE_NOT_DETECTED' }
  if(-not $p.school_coordination_hint){ throw 'TESTLIFE_COORD_HINT_MISSING' }
  if($p.school_coordination_hint.policy -ne 'COORDINATE_WITH_SCHOOL_NOT_BLOCK_SAFE_MODE'){ throw 'TESTLIFE_COORD_POLICY_BAD' }
  if([bool]$p.memory_coordination.direct_active_memory_write_allowed -ne $false){ throw 'TESTLIFE_DIRECT_WRITE_NOT_FALSE' }
  if([bool]$p.memory_coordination.intake_required_for_agentlife_packets -ne $true){ throw 'TESTLIFE_INTAKE_REQUIRED_NOT_TRUE' }
  if([bool]$p.memory_coordination.merge_lock_active -ne $true){ throw 'TESTLIFE_MERGE_LOCK_NOT_TRUE' }
  if([bool]$p.memory_coordination.backoff_required -ne $true){ throw 'TESTLIFE_BACKOFF_NOT_TRUE' }
  if([bool]$p.mutation_audit.active_memory_mutated -ne $false){ throw 'TESTLIFE_ACTIVE_MEMORY_MUTATED' }
  if([bool]$p.memory_state.unchanged -ne $true){ throw 'TESTLIFE_MEMORY_CHANGED' }
  if([int]$p.test_life.total_cycles -lt 1){ throw 'TESTLIFE_NO_CYCLES' }
  if($p.stop_reason -eq 'BLOCKED_BY_ACTIVE_SCHOOL'){ throw 'TESTLIFE_OLD_BLOCK_STOP_REASON' }
  Write-Host 'ASSERT_TESTLIFE_COMPAT_PASS=TRUE'
  Write-Host ('ASSERT_TESTLIFE_CYCLES=' + $p.test_life.total_cycles)
  Write-Host ('ASSERT_SCHOOL_ACTIVE=' + $p.school_state.active_detected)
  Write-Host ('ASSERT_BACKOFF_REQUIRED=' + $p.memory_coordination.backoff_required)
  Write-Host ('ASSERT_MEMORY_UNCHANGED=' + $p.memory_state.unchanged)
  $tracked=\"operations/autonomous_inner_motor/test_life_runs/$runId/AIMO_TESTLIFE_SCHOOL_COMPAT_PROOF.json\"
  [ordered]@{
    schema='tracked_aimo_testlife_school_compat_probe_v1'
    status='PASS_AIMO_TESTLIFE_SCHOOL_COMPATIBILITY_V1'
    created_at=(Get-Date).ToString('o')
    test_life_proof=$proof
    cycles=[int]$p.test_life.total_cycles
    school_active_detected=[bool]$p.school_state.active_detected
    coordination_policy=$p.school_coordination_hint.policy
    direct_active_memory_write_allowed=[bool]$p.memory_coordination.direct_active_memory_write_allowed
    intake_required_for_agentlife_packets=[bool]$p.memory_coordination.intake_required_for_agentlife_packets
    merge_lock_active=[bool]$p.memory_coordination.merge_lock_active
    backoff_required=[bool]$p.memory_coordination.backoff_required
    active_memory_mutated=[bool]$p.mutation_audit.active_memory_mutated
    memory_unchanged=[bool]$p.memory_state.unchanged
    stop_reason=$p.stop_reason
    stdout=$stdout
    stderr=$stderr
    boundary='Proves SandboxTestLife can run agent-life cycles while school is active and merge queue lock is active; memory remains unchanged and direct active memory write remains forbidden.'
  } | ConvertTo-Json -Depth 60 | Set-Content -LiteralPath $tracked -Encoding UTF8
  Write-Host ('TRACKED_PROOF=' + $tracked)
} finally {
  if(Test-Path $lockPath){ Remove-Item -LiteralPath $lockPath -Force }
  if($aimo -and -not $aimo.HasExited){ Stop-Process -Id $aimo.Id -Force }
  if($dummy -and -not $dummy.HasExited){ Stop-Process -Id $dummy.Id -Force }
}
Write-Host ('POST_CLEAN_LOCK_EXISTS=' + (Test-Path $lockPath))
Write-Host 'STATUS_START'; git status --short --untracked-files=all; Write-Host 'STATUS_END'
Write-Host 'AIMO_SANDBOX_TESTLIFE_SCHOOL_COMPAT_PROOF_END'
}
$bridgeCommandSucceeded = $?
$bridgeLastExitCode = $global:LASTEXITCODE
if ($null -ne $bridgeLastExitCode) { exit $bridgeLastExitCode }
if ($bridgeCommandSucceeded) { exit 0 }
exit 1"
